() => {
  const url = pm.collectionVariables.get('url');
  const random = pm.variables.replaceIn('{{$randomWord}}');
  const timestamp = Date.now();
  const username = `vlad${random}${timestamp}`;
  const email = `vlad${random}${timestamp}@gmail.com`;
  const password = pm.collectionVariables.get('passwordConduit');

  const signUpRequest = {
    url: url + 'users',
    method: 'POST',
    header: {
      'Content-Type': 'application/json',
    },
    body: {
      mode: 'raw',
      raw: JSON.stringify({
        user: {
          username: username,
          email: email,
          password: password,
        }
      })
    }
  };

  pm.sendRequest(signUpRequest, (error, response) => {
    console.log(error ? error : response.json());
    pm.environment.set('email', response.json().user.email);
    pm.environment.set('token', response.json().user.token);
    pm.environment.set('username', response.json().user.username);

  });
}

() => {
  const url = pm.collectionVariables.get('url');
  const token = pm.environment.get('token');
  const random = pm.variables.replaceIn('{{$randomWord}}');

  const title = `testTitle_${random}`;
  const description = `testDescription_${random}`;
  const body = `testBody_${random}`;
  const tag = `testTag_${random}`;

  const createArticleRequest = {
    url: url + 'articles',
    method: 'POST',
    header: {
      'Content-Type': 'application/json',
      'Authorization': `Token ${token}`
    },
    body: {
      mode: 'raw',
      raw: JSON.stringify({
        article: {
          title: title,
          description: description,
          body: body,
          tagList: [tag]
        }
      })
    }
  };

  pm.sendRequest(createArticleRequest, (error, response) => {
    console.log(error ? error : response.json());

    const article = response.json().article;
    pm.environment.set('articleSlug', article.slug);
    pm.environment.set('articleTag', article.tagList);
  });
}

() => {
  const url = pm.collectionVariables.get('url');
  const token = pm.environment.get('token');
  const slug = pm.environment.get('articleSlug');

  if (!slug) return;

  pm.sendRequest({
    url: url + `articles/${slug}`,
    method: 'DELETE',
    header: {
      Authorization: `Token ${token}`
    }
  });
}

() => {
  const url = pm.collectionVariables.get('url');
  const token = pm.environment.get('token');
  const articleSlug = pm.environment.get('articleSlug');

  const commentBody = `exampleСomment`;

  const createCommentRequest = {
    url: `${url}articles/${articleSlug}/comments`,
    method: 'POST',
    header: {
      'Content-Type': 'application/json',
      'Authorization': `Token ${token}`
    },
    body: {
      mode: 'raw',
      raw: JSON.stringify({
        comment: {
          body: commentBody
        }
      })
    }
  };

  pm.sendRequest(createCommentRequest, (error, response) => {
    console.log(error ? error : response.json());

    const comment = response.json().comment;
    pm.environment.set('commentId', comment.id);
  });
}
